"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useSession } from "next-auth/react";
import {
  LayoutDashboard, Users, BarChart2, X, ChevronRight,
  ShieldCheck, ShieldAlert, Heart, CalendarClock, Settings, ClipboardList,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { getInitials } from "@/lib/utils";

type NavItem  = { href: string; label: string; icon: React.ElementType };
type NavGroup = { label: string; items: NavItem[] };

/* Spec §4.1 — 8 nav items */
const navGroups: NavGroup[] = [
  {
    label: "Overview",
    items: [
      { href: "/hr/dashboard", label: "Dashboard", icon: LayoutDashboard },
      { href: "/hr/employees", label: "Employees", icon: Users },
    ],
  },
  {
    label: "Compliance & Wellness",
    items: [
      { href: "/hr/compliance", label: "PE Compliance",   icon: ShieldAlert },
      { href: "/hr/wellness",   label: "Wellness Trends", icon: Heart },
    ],
  },
  {
    label: "Reports & Tools",
    items: [
      { href: "/hr/reports",    label: "Reports & Exports", icon: BarChart2 },
      { href: "/hr/scheduling", label: "Bulk Scheduling",   icon: CalendarClock },
      { href: "/hr/audit",      label: "Audit Trail",       icon: ClipboardList },
    ],
  },
  {
    label: "System",
    items: [
      { href: "/hr/settings", label: "Account Settings", icon: Settings },
    ],
  },
];

interface HrSidebarProps {
  isOpen?: boolean;
  onClose?: () => void;
}

export function HrSidebar({ isOpen = true, onClose }: HrSidebarProps) {
  const pathname = usePathname();
  const { data: session } = useSession();

  const firstName = session?.user?.firstName ?? "";
  const lastName  = session?.user?.lastName  ?? "";
  const initials  = firstName && lastName ? getInitials(firstName, lastName) : "HR";

  return (
    <>
      {/* Mobile backdrop */}
      {isOpen && onClose && (
        <div
          className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm lg:hidden"
          onClick={onClose}
        />
      )}

      <aside
        className={[
          "fixed inset-y-0 left-0 z-50 flex flex-col",
          "lg:static lg:translate-x-0",
          "transition-transform duration-300 ease-in-out",
          isOpen ? "translate-x-0" : "-translate-x-full",
        ].join(" ")}
        style={{
          width: 240,
          flexShrink: 0,
          backgroundColor: "#08036A",
          borderRight: "3px solid #E00500",
          height: "100vh",
          overflowY: "auto",
        }}
      >
        {/* ── Brand section ── */}
        <div style={{
          padding: "16px 20px",
          borderBottom: "3px solid #E00500",
          background: "#06024f",
        }}>
          <Link href="/hr/dashboard" style={{ display: "flex", flexDirection: "column", gap: 6, textDecoration: "none" }}>
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img src="/nwdi-logo.png" alt="NWDI" style={{ width: "100%", height: 36, objectFit: "contain", objectPosition: "left" }} />
            <p style={{ fontSize: "0.62rem", color: "rgba(255,255,255,0.45)", letterSpacing: "0.06em", textTransform: "uppercase" }}>
              HR Staff Portal
            </p>
          </Link>
          {onClose && (
            <Button
              variant="ghost" size="icon"
              className="lg:hidden absolute top-3 right-3"
              style={{ color: "rgba(255,255,255,0.7)" }}
              onClick={onClose}
            >
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>

        {/* ── User section ── */}
        <div style={{
          padding: "16px 20px",
          borderBottom: "1px solid rgba(255,255,255,0.08)",
          display: "flex", alignItems: "center", gap: 10,
        }}>
          <div style={{
            width: 34, height: 34, borderRadius: 8, flexShrink: 0,
            background: "#E00500",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: "0.75rem", fontWeight: 700, color: "white",
          }}>
            {initials}
          </div>
          <div style={{ overflow: "hidden", flex: 1 }}>
            <p style={{
              fontSize: "0.82rem", fontWeight: 600, color: "white",
              whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
            }}>
              {firstName} {lastName}
            </p>
            <p style={{ fontSize: "0.7rem", color: "rgba(255,255,255,0.5)" }}>HR Staff</p>
          </div>
          <div style={{
            padding: "1px 7px", borderRadius: 10,
            background: "#E00500",
            fontSize: "0.65rem", fontWeight: 700, color: "white", letterSpacing: "0.06em",
          }}>
            HR
          </div>
        </div>

        {/* ── Navigation ── */}
        <nav style={{ flex: 1, padding: "12px 0", overflowY: "auto" }}>
          {navGroups.map((group) => (
            <div key={group.label}>
              <p style={{
                padding: "12px 20px 6px",
                fontSize: "0.65rem", fontWeight: 700, letterSpacing: "0.12em",
                textTransform: "uppercase", color: "rgba(255,255,255,0.3)",
              }}>
                {group.label}
              </p>
              {group.items.map((item) => {
                const isActive = pathname === item.href ||
                  (item.href !== "/hr/dashboard" && pathname.startsWith(item.href));
                const Icon = item.icon;
                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    onClick={onClose}
                    style={{
                      display: "flex", alignItems: "center", gap: 10,
                      padding: "9px 20px",
                      fontSize: "0.86rem", color: isActive ? "white" : "rgba(255,255,255,0.65)",
                      borderLeft: `3px solid ${isActive ? "#E00500" : "transparent"}`,
                      background: isActive ? "rgba(224,5,0,0.15)" : "transparent",
                      transition: "all 0.2s",
                      textDecoration: "none",
                    }}
                    className="hover:bg-white/6 hover:text-white"
                  >
                    <span style={{ width: 20, textAlign: "center", flexShrink: 0 }}>
                      <Icon style={{ width: 16, height: 16, color: isActive ? "white" : "rgba(255,255,255,0.6)" }} />
                    </span>
                    <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                      {item.label}
                    </span>
                  </Link>
                );
              })}
            </div>
          ))}
        </nav>

        {/* ── Tagline ── */}
        <div style={{
          padding: "8px 20px",
          borderTop: "1px solid rgba(255,255,255,0.08)",
          borderBottom: "1px solid rgba(255,255,255,0.08)",
        }}>
          <p style={{
            fontSize: "0.65rem", color: "rgba(255,255,255,0.25)",
            fontStyle: "italic", letterSpacing: "0.04em", textAlign: "center",
          }}>
            "Your Health is Our Commitment"
          </p>
        </div>

        {/* ── Footer ── */}
        <div style={{ padding: "16px 20px", borderTop: "1px solid rgba(255,255,255,0.08)" }}>
          <Link
            href="/hr/settings"
            style={{
              display: "flex", alignItems: "center", gap: 10,
              padding: "8px 12px", borderRadius: 8,
              textDecoration: "none", transition: "background 0.2s",
            }}
            className="hover:bg-white/10"
          >
            <div style={{
              width: 34, height: 34, borderRadius: 8, flexShrink: 0,
              background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.15)",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: "0.75rem", fontWeight: 700, color: "white",
            }}>
              {initials}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <p style={{
                fontSize: "0.82rem", fontWeight: 600, color: "white",
                whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
              }}>
                {firstName} {lastName}
              </p>
              <p style={{ fontSize: "0.7rem", color: "rgba(255,255,255,0.45)", marginTop: 1 }}>
                Account settings
              </p>
            </div>
            <ChevronRight style={{ width: 14, height: 14, color: "rgba(255,255,255,0.3)", flexShrink: 0 }} />
          </Link>
        </div>
      </aside>
    </>
  );
}
